const body = $input.first().json.body || {};
const ids = body.resultado_ids;
if (!Array.isArray(ids) || ids.length === 0) {
  throw new Error('Payload inválido: se requiere resultado_ids como array no vacío');
}
if (ids.length > 200) {
  throw new Error('Máximo 200 resultados por solicitud');
}
// Anti-replay opcional: si el frontend manda ts (epoch seg), rechazar solicitudes viejas
const ts = Number(body.ts || 0);
if (ts && Math.abs(Date.now() / 1000 - ts) > 300) {
  throw new Error('Solicitud expirada (anti-replay)');
}
return [{ json: { resultado_ids: ids } }];

const it = $json;
if (!it.email || !it.pdf_filename) {
  throw new Error(`Registro incompleto para folio ${it.folio || '?'} (falta email o pdf_filename)`);
}
const id = `${it.folio}_${Date.now()}_${Math.floor(Math.random() * 1000)}`;
const nombre = it.nombre_destinatario || 'paciente';
const cuerpo = [
  `<p>Estimado(a) ${nombre}:</p>`,
  '<p>Le hacemos llegar en el documento adjunto los resultados del estudio realizado por el Instituto de Atención Integral de Enfermedades Renales (INAER).</p>',
  '<p>Si tiene dudas sobre la interpretación de los resultados, le invitamos a acudir a su unidad de salud o comunicarse con nosotros.</p>',
  '<p>Este mensaje y su adjunto contienen información confidencial dirigida exclusivamente a su destinatario. Si lo recibió por error, le pedimos eliminarlo y notificarlo a este remitente.</p>',
  '<p>Atentamente,<br>INAER — Detección Oportuna y Registro<br>Gobierno del Estado de Aguascalientes</p>'
].join('');
return {
  json: {
    id,
    para: it.email,
    cc: '',
    asunto: `Resultados de laboratorio — Folio ${it.folio}`,
    cuerpo_html: cuerpo,
    cifrar_pdf: false,
    password_pdf: '',
    pdf_filename: it.pdf_filename,
    id_envio: it.id_envio ?? it.folio
  }
};

const items = $input.all();
return [{ json: {
  ok: true,
  encolados: items.length,
  ids: items.map(i => i.json.id)
} }];

const json = $json;
const binaryData = $binary.data.data;

return {
  json: {
    ...json,
    pdf_base64: binaryData
  }
};
